import{_ as e,o as a,c as l,a2 as n}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"圜丘坛","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/temple-of-heaven/huanqiu-tan.md","filePath":"landmarks/temple-of-heaven/huanqiu-tan.md","lastUpdated":1784720050000}'),o={name:"landmarks/temple-of-heaven/huanqiu-tan.md"};function r(i,t,s,d,h,g){return a(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="圜丘坛" tabindex="-1">圜丘坛 <a class="header-anchor" href="#圜丘坛" aria-label="Permalink to &quot;圜丘坛&quot;">​</a></h1><p><img src="https://plus.unsplash.com/premium_photo-1694475674589-65457ca58004?w=1200&amp;q=80" alt="圜丘坛"></p><blockquote><p>&quot;九九归一，坛上通天。一步一阶，皆是天数。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>圜丘坛位于天坛内坛南部，是<strong>明清两代皇帝冬至日祭天的祭坛</strong>，建于明嘉靖九年（1530年），清乾隆十四年（1749年）扩建为今日规模。每年冬至日&quot;一阳初生&quot;之际，皇帝在此燔柴迎帝、行礼告天——这是古代中国最高等级的国家典礼。</p><p>圜丘坛是一座<strong>三层汉白玉露天圆坛</strong>，没有屋顶，因为祭天必须&quot;露祭&quot;，直接面对苍穹。坛外环绕两重围墙：内墙圆形、外墙方形，取&quot;天圆地方&quot;之意；四面各设棂星门，形制严整。</p><p>整座坛台是一部用石头写成的&quot;九&quot;之颂歌：坛面、台阶、栏板所用石块，<strong>全部为九或九的倍数</strong>。在中国传统文化中，九为阳数之极，&quot;九重天&quot;是天帝的居所，圜丘以层层累九的方式，把&quot;天数&quot;凝固在建筑之中。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><p><img src="https://images.unsplash.com/photo-1706066496354-26c7e0e2ad04?w=1200&amp;q=80" alt="圜丘坛汉白玉栏板"></p><p>圜丘坛三层圆坛自下而上逐层收分，各层直径暗合圆周率之妙：</p><table tabindex="0"><thead><tr><th style="text-align:left;">层级</th><th style="text-align:center;">坛面直径</th><th style="text-align:center;">栏板数</th><th style="text-align:center;">台阶</th></tr></thead><tbody><tr><td style="text-align:left;">上层</td><td style="text-align:center;">23.6米</td><td style="text-align:center;">72块（9×8）</td><td style="text-align:center;">每面9级</td></tr><tr><td style="text-align:left;">中层</td><td style="text-align:center;">31.4米</td><td style="text-align:center;">108块（9×12）</td><td style="text-align:center;">每面9级</td></tr><tr><td style="text-align:left;">下层</td><td style="text-align:center;">47.2米</td><td style="text-align:center;">180块（9×20）</td><td style="text-align:center;">每面9级</td></tr></tbody></table><p>坛面铺石更是一座数字迷宫：中心为一整块圆形天心石，向外第一圈铺9块，第二圈18块，第三圈27块……直到第九圈81块（9×9）；三层坛面皆循此制。从任何一面登台，台阶均为九级。<strong>放眼望去，整座圜丘无一石不是九的倍数</strong>。</p><p>圜丘坛周围还分布着与祭祀密切相关的附属建筑：东侧的神厨、神库（备办祭品）与三座宰牲亭，院外的燔柴炉、瘗坎（埋祭物之所），以及矗立的望灯杆。北出棂星门即达供奉神牌的<a href="/beijing-travel-guide/landmarks/temple-of-heaven/huangqiong-yu.html">皇穹宇</a>。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="天心石与-亿兆景从" tabindex="-1">天心石与&quot;亿兆景从&quot; <a class="header-anchor" href="#天心石与-亿兆景从" aria-label="Permalink to &quot;天心石与&quot;亿兆景从&quot;&quot;">​</a></h3><p>上层坛面正中的圆形中心石，名为<strong>天心石</strong>（又称太极石、亿兆景从石）。人站上石面高声呼喊或拍手，会听到明显被放大的共鸣之声，仿佛上天回应。古人视之为&quot;皇天垂听&quot;的神迹，取名&quot;亿兆景从&quot;，寓意帝王一呼而亿兆响应。</p><p>现代声学揭示了谜底：天心石恰在圆形坛面的几何中心，声波向四周传播后，被环列的栏板和坛面反射回来，在中心点汇聚叠加，于是声音被显著加强。古人的敬畏与今人的科学，在同一块石头上达成了默契。</p><h3 id="冬至大祀" tabindex="-1">冬至大祀 <a class="header-anchor" href="#冬至大祀" aria-label="Permalink to &quot;冬至大祀&quot;">​</a></h3><p>祭天大典于冬至日凌晨开始：坛上燃起燔柴炉中的燎火，烟气上达于天；皇帝身着蓝色祭服，在中和韶乐的伴奏下行三跪九叩大礼，向&quot;皇天上帝&quot;神牌献帛献爵。整个仪程有数百名执事、乐舞生参与，庄严肃穆，是明清国家礼仪的最高形态。</p><h3 id="乾隆扩建换汉白玉" tabindex="-1">乾隆扩建换汉白玉 <a class="header-anchor" href="#乾隆扩建换汉白玉" aria-label="Permalink to &quot;乾隆扩建换汉白玉&quot;">​</a></h3><p>圜丘坛初建于嘉靖九年（1530年），原为青色琉璃砖砌筑。清乾隆十四年（1749年），因坛制偏狭、不合礼数，乾隆帝下旨按&quot;九&quot;数体系全面扩建，并改用纯白汉白玉——坛面更阔、栏板更精，&quot;三层累九&quot;的数理格局至此定型。今日所见的洁白坛体，即乾隆朝的手笔。</p><h2 id="最佳游览季节" tabindex="-1">最佳游览季节 <a class="header-anchor" href="#最佳游览季节" aria-label="Permalink to &quot;最佳游览季节&quot;">​</a></h2><p>圜丘为露天圆坛，游览体验与天气紧密相关。晴朗冬日阳光斜照，汉白玉泛着暖光，最合&quot;冬至祭天&quot;的原境；雪后白玉铺坛则是公认的最美时刻。夏季坛面无遮，正午暴晒，建议避开 12:00-14:00 时段。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><p><strong>天心石回声</strong> 站上中心石拍手或说话，亲身感受声波聚焦的奇妙效果（游客多时需排队）。</p></li><li><p><strong>&quot;九&quot;的倍数密码</strong> 数一数栏板、台阶、铺石圈数，验证处处皆九的礼制设计。</p></li><li><p><strong>三层圆坛的尺度感</strong> 自下而上逐层缩小，仰观只见坛面与天空，极简之中尽显神圣。</p></li><li><p><strong>圆形内墙与方形外墙</strong> 内外两重墙垣方圆相套，直观呈现&quot;天圆地方&quot;的宇宙模型。</p></li><li><p><strong>燔柴炉与望灯杆</strong> 坛外这些祭典遗存，是理解冬至祭天仪程的实物线索。</p></li><li><p><strong>棂星门石雕</strong> 四面棂星门的汉白玉门枕石与云纹雕刻，工艺精细，常被匆忙的游客忽略。</p></li><li><p><strong>神厨神库</strong> 坛东的神厨、神库与宰牲亭是祭品备办之所，陈列祭器复原场景，补足祭典全貌。</p></li></ol><h2 id="最佳拍照点" tabindex="-1">最佳拍照点 <a class="header-anchor" href="#最佳拍照点" aria-label="Permalink to &quot;最佳拍照点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">机位</th><th style="text-align:left;">画面</th><th style="text-align:left;">建议时间</th></tr></thead><tbody><tr><td style="text-align:left;">天心石处超广角仰拍</td><td style="text-align:left;">放射状铺石 + 纯净天空</td><td style="text-align:left;">上午人少时</td></tr><tr><td style="text-align:left;">三层坛面边缘</td><td style="text-align:left;">汉白玉栏板的曲线韵律</td><td style="text-align:left;">清晨顺光</td></tr><tr><td style="text-align:left;">棂星门外回望</td><td style="text-align:left;">坛门与圆坛的礼制构图</td><td style="text-align:left;">全天</td></tr><tr><td style="text-align:left;">燔柴炉旁</td><td style="text-align:left;">燎炉与圆坛同框，交代祭典场景</td><td style="text-align:left;">下午斜阳</td></tr></tbody></table><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li><strong>建议南门进园</strong>：圜丘坛靠近天坛南门（昭亨门），进门即达，是精华路线的第一站。</li><li><strong>上午顺光</strong>：圜丘开阔无遮，上午游览光线最佳，也便于拍摄坛面几何纹理。</li><li><strong>天心石体验</strong>：旺季排队较长，可早到或临近闭园时再试。</li><li><strong>向北衔接</strong>：圜丘坛北即<a href="/beijing-travel-guide/landmarks/temple-of-heaven/huangqiong-yu.html">皇穹宇</a>，再沿<a href="/beijing-travel-guide/landmarks/temple-of-heaven/danbi-qiao.html">丹陛桥</a>北上可达<a href="/beijing-travel-guide/landmarks/temple-of-heaven/qinian-dian.html">祈年殿</a>，动线一气呵成。</li><li><strong>冬季别有意境</strong>：雪后圜丘白玉铺陈，最接近古人&quot;冬至露祭&quot;的现场感。</li><li><strong>带一份&quot;九&quot;的清单</strong>：行前记牢&quot;九、十八、二十七……八十一&quot;的圈数序列，现场逐圈验证，乐趣倍增。</li></ol><h2 id="相关景点" tabindex="-1">相关景点 <a class="header-anchor" href="#相关景点" aria-label="Permalink to &quot;相关景点&quot;">​</a></h2><ul><li><a href="/beijing-travel-guide/landmarks/temple-of-heaven/huangqiong-yu.html">皇穹宇与回音壁</a>：圜丘坛正北，神牌的日常供奉之所</li><li><a href="/beijing-travel-guide/landmarks/temple-of-heaven/danbi-qiao.html">丹陛桥</a>：自圜丘成贞门北上即登神路</li><li><a href="/beijing-travel-guide/landmarks/temple-of-heaven/qinian-dian.html">祈年殿</a>：神路北端的祈谷大殿，天坛标志</li></ul><hr><p><strong>📍 位置</strong>：天坛内坛南部中轴线（南门内） <strong>⏱️ 建议游览</strong>：30-45分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/temple-of-heaven/">天坛概览</a></p>',33)])])}const p=e(o,[["render",r]]);export{q as __pageData,p as default};
